const SEED_USERS = [
  { name: "Pride Dube", email: "pride@pwdxperts.co.za", role: "system_admin", province: "" },
  { name: "Peter Williams", email: "peter@cogta.gov.za", role: "system_admin", province: "" },
  { name: "Gauteng Coordinator", email: "gauteng@cogta.gov.za", role: "provincial_coordinator", province: "Gauteng" },
  { name: "KwaZulu-Natal Coordinator", email: "kwazulunatal@cogta.gov.za", role: "provincial_coordinator", province: "KwaZulu-Natal" },
  { name: "Eastern Cape Coordinator", email: "easterncape@cogta.gov.za", role: "provincial_coordinator", province: "Eastern Cape" },
  { name: "Free State Coordinator", email: "freestate@cogta.gov.za", role: "provincial_coordinator", province: "Free State" },
  { name: "Limpopo Coordinator", email: "limpopo@cogta.gov.za", role: "provincial_coordinator", province: "Limpopo" },
  { name: "Mpumalanga Coordinator", email: "mpumalanga@cogta.gov.za", role: "provincial_coordinator", province: "Mpumalanga" },
  { name: "North West Coordinator", email: "northwest@cogta.gov.za", role: "provincial_coordinator", province: "North West" },
  { name: "Northern Cape Coordinator", email: "northerncape@cogta.gov.za", role: "provincial_coordinator", province: "Northern Cape" },
  { name: "Hub Analyst", email: "analyst@cogta.gov.za", role: "hub_analyst", province: "" },
  { name: "Rapid Response Team", email: "rapid@cogta.gov.za", role: "rapid_response", province: "" },
];

const PROVINCES = ["Eastern Cape","Free State","Gauteng","KwaZulu-Natal","Limpopo","Mpumalanga","North West","Northern Cape","Western Cape"];
const SECTORS = ["Water Services","Electricity Supply","Roads & Transport","Waste Management","Human Settlements","Governance & Financial Distress","Health Services","Multi-Service","Infrastructure","Environment","Education","Other"];

export async function POST(request: NextRequest) {
  const secret = request.headers.get("x-seed-secret");
  if (secret !== "CoGTA-seed-2026") {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const results: any = { users: 0, provinces: 0, sectors: 0, districts: 0, municipalities: 0, cases: 0, skipped: 0, errors: [] };

  try {
    // 1. Create/ensure provinces
    const provinceMap: Record<string, string> = {};
    for (const name of PROVINCES) {
      const p = await prisma.province.upsert({
        where: { name },
        update: {},
        create: { name },
      });
      provinceMap[name] = p.id;
      results.provinces++;
    }

    // 2. Create/ensure sectors
    const sectorMap: Record<string, string> = {};
    for (const name of SECTORS) {
      const s = await prisma.sector.upsert({
        where: { name },
        update: {},
        create: { name, active: true },
      });
      sectorMap[name] = s.id;
      results.sectors++;
    }

    // 3. Create/ensure districts and municipalities
    const districtMap: Record<string, string> = {};
    const muniMap: Record<string, string> = {};
    const districtsSeen = new Set<string>();
    const munisSeen = new Set<string>();

    for (const c of SEED_CASES) {
      if (c.province && c.district && provinceMap[c.province]) {
        const distKey = `${c.province}::${c.district}`;
        if (!districtsSeen.has(distKey)) {
          districtsSeen.add(distKey);
          const d = await prisma.district.upsert({
            where: { name_provinceId: { name: c.district, provinceId: provinceMap[c.province] } },
            update: {},
            create: { name: c.district, provinceId: provinceMap[c.province] },
          });
          districtMap[distKey] = d.id;
          results.districts++;
        } else {
          const d = await prisma.district.findFirst({ where: { name: c.district, provinceId: provinceMap[c.province] }, select: { id: true } });
          if (d) districtMap[distKey] = d.id;
        }

        if (c.municipality && districtMap[distKey]) {
          const muniKey = `${distKey}::${c.municipality}`;
          if (!munisSeen.has(muniKey)) {
            munisSeen.add(muniKey);
            const m = await prisma.municipality.upsert({
              where: { name_districtId: { name: c.municipality, districtId: districtMap[distKey] } },
              update: {},
              create: { name: c.municipality, districtId: districtMap[distKey] },
            });
            muniMap[muniKey] = m.id;
            results.municipalities++;
          } else {
            const m = await prisma.municipality.findFirst({ where: { name: c.municipality, districtId: districtMap[distKey] }, select: { id: true } });
            if (m) muniMap[muniKey] = m.id;
          }
        }
      }
    }

    // 4. Create/ensure users
    const passwordHash = await bcrypt.hash("CoGTA2026!", 10);
    for (const u of SEED_USERS) {
      try {
        await prisma.user.upsert({
          where: { email: u.email },
          update: { role: u.role, province: u.province || null, active: true },
          create: {
            name: u.name, email: u.email, password: passwordHash,
            role: u.role, province: u.province || null, active: true,
          },
        });
        results.users++;
      } catch (e: any) {
        results.errors.push(`User ${u.email}: ${e.message}`);
      }
    }

    // 5. Import cases
    for (const c of SEED_CASES) {
      try {
        const existing = await prisma.case.findFirst({ where: { referenceNumber: c.ref } });
        if (existing) { results.skipped++; continue; }

        const provinceId = provinceMap[c.province] || null;
        const distKey = `${c.province}::${c.district}`;
        const muniKey = `${distKey}::${c.municipality}`;
        const districtId = districtMap[distKey] || null;
        const municipalityId = muniMap[muniKey] || null;
        const sectorId = sectorMap[c.sector] || null;

        await prisma.case.create({
          data: {
            referenceNumber: c.ref,
            title: c.title || c.description.substring(0, 120),
            description: c.description,
            intakeChannel: "municipal_report",
            reporterType: c.source || null,
            reporterContact: c.contact || null,
            ward: c.ward || null,
            provinceId,
            districtId,
            municipalityId,
            sectorId,
            subCategory: c.subCategory || null,
            severityLevel: c.severity || "Moderate",
            severityScore: c.severity === "Critical" ? 80 : c.severity === "High" ? 60 : c.severity === "Moderate" ? 40 : 20,
            isRecurring: c.recurring || false,
            populationAffected: c.population || 0,
            responsibleSphere: c.responsibleSphere || "Municipal",
            implementingAgent: c.implementingAgent || null,
            accountableOfficial: c.accountableOfficial || null,
            contactDetails: c.contact || null,
            actionPlan: c.immediateAction || null,
            status: (c.status as any) || "new_submission",
            escalationLevel: c.escalationLevel === "none" ? null : c.escalationLevel || null,
            resolutionNotes: c.resolutionDesc || null,
            closeOutStatus: c.closeOutStatus || null,
          },
        });
        results.cases++;
      } catch (e: any) {
        results.errors.push(`Case ${c.ref}: ${e.message?.substring(0, 100)}`);
      }
    }

    return NextResponse.json({ success: true, results });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function GET() {
  const counts = await Promise.all([
    prisma.case.count(),
    prisma.user.count(),
    prisma.province.count(),
    prisma.sector.count(),
  ]);
  return NextResponse.json({
    cases: counts[0], users: counts[1], provinces: counts[2], sectors: counts[3],
    message: "POST with header x-seed-secret: CoGTA-seed-2026 to run seed"
  });
}
